# Example task: Write a package main stdlib-only JSON HTTP endpoint: POST /echo decodes a JSON body with encoding/json, validates it, and responds with JSON plus Content-Type application/json; 405 for non-POST, 400 for invalid/empty input, 200 on success. Expose newMux() *http.ServeMux.
```go
package main

import (
	"encoding/json"
	"net/http"
)

type echoRequest struct {
	Message string `json:"message"`
}

type echoResponse struct {
	Echo   string `json:"echo"`
	Length int    `json:"length"`
}

// newMux exposes POST /echo: decode a JSON body, validate it, and respond with
// JSON. Standard library only — encoding/json + net/http.
func newMux() *http.ServeMux {
	mux := http.NewServeMux()
	mux.HandleFunc("/echo", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
			return
		}
		var req echoRequest
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			http.Error(w, "invalid json", http.StatusBadRequest)
			return
		}
		if req.Message == "" {
			http.Error(w, "message required", http.StatusBadRequest)
			return
		}
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		json.NewEncoder(w).Encode(echoResponse{Echo: req.Message, Length: len(req.Message)})
	})
	return mux
}

func main() {
	http.ListenAndServe(":8080", newMux())
}
```
# Example task: Write a package main HTTP handler that wires an http.ServeMux (standard library only, no third-party router) for GET /kv/{key} and PUT /kv/{key} backed by an in-memory store. Use the Go 1.22+ method+wildcard route patterns and r.PathValue. PUT returns 201 Created, GET returns the value (200) or 404 if absent. Expose newMux(s *Store) *http.ServeMux.
```go
package main

import (
	"io"
	"net/http"
	"sync"
)

type Store struct {
	mu sync.RWMutex
	m  map[string]string
}

func NewStore() *Store { return &Store{m: make(map[string]string)} }

func (s *Store) Get(key string) (string, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	v, ok := s.m[key]
	return v, ok
}

func (s *Store) Set(key, value string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.m[key] = value
}

// newMux wires routes with the Go 1.22+ method+wildcard ServeMux patterns —
// no third-party router. r.PathValue extracts the {key} segment.
func newMux(s *Store) *http.ServeMux {
	mux := http.NewServeMux()
	mux.HandleFunc("GET /kv/{key}", func(w http.ResponseWriter, r *http.Request) {
		v, ok := s.Get(r.PathValue("key"))
		if !ok {
			http.Error(w, "not found", http.StatusNotFound)
			return
		}
		w.Header().Set("Content-Type", "text/plain")
		io.WriteString(w, v)
	})
	mux.HandleFunc("PUT /kv/{key}", func(w http.ResponseWriter, r *http.Request) {
		body, err := io.ReadAll(r.Body)
		if err != nil {
			http.Error(w, "bad body", http.StatusBadRequest)
			return
		}
		s.Set(r.PathValue("key"), string(body))
		w.WriteHeader(http.StatusCreated)
	})
	return mux
}

func main() {
	http.ListenAndServe(":8080", newMux(NewStore()))
}
```

